window.I18N={"404":{"h1":"페이지를 찾을 수 없습니다","message":"계산기를 찾고 계신가요?","go_home":"홈페이지로 이동"},"site":{"title":"TurfCalculator","description":"주택 소유자를 위한 무료 잔디 및 잔디밭 계산기","tagline":"무료 계산기 — 가입 없이, 번거로움 없이"},"nav":{"home":"홈","sod_calculator":"잔디 계산기","lawn_area_calculator":"잔디밭 면적 계산기","grass_type_guide":"잔디 종류","grass_seed_calculator":"잔디 씨앗 계산기","fertilizer_calculator":"비료 계산기","lawn_water_calculator":"물 계산기","soil_calculator":"토양 계산기","area_converter":"면적 변환기","lawn_care_calendar":"관리 캘린더","about":"소개","privacy":"개인정보 처리방침","terms":"이용약관","disclaimer":"면책 조항","cookies":"쿠키 정책","language":"언어"},"pages":{"sod-calculator":"잔디-계산기","lawn-area-calculator":"잔디밭-면적-계산기","grass-type-guide":"잔디-종류","grass-seed-calculator":"잔디-씨앗-계산기","fertilizer-calculator":"비료-계산기","lawn-water-calculator":"물-계산기","soil-calculator":"토양-계산기","area-converter":"면적-변환기","lawn-care-calendar":"잔디-관리-캘린더","about":"소개","privacy-policy":"개인정보-처리방침","terms":"이용약관","disclaimer":"면책-조항","cookie-policy":"쿠키-정책"},"common":{"calculate":"계산","reset":"초기화","result":"결과","results":"결과","area":"면적","length":"길이","width":"폭","diameter":"지름","depth":"깊이","unit_ft":"ft","unit_m":"m","unit_in":"in","unit_cm":"cm","unit_sqft":"ft²","unit_sqm":"m²","unit_sqyd":"yd²","unit_ac":"에이커","unit_ha":"헥타르","grass_type":"잔디 종류","includes_extra":"절단 및 성형을 위해 {percent}% 여유분 포함","based_on_area":"{area} {unit} 잔디밭 기준","need_different":"다른 모양이나 롤 사이즈가 필요하신가요?","add_another_area":"+ 다른 면적 추가","subtract_area":"− 면적 빼기 (수영장, 집, 진입로)","total":"합계","send_to_sod":"→ 잔디가 얼마나 필요한지 계산","or":"또는","est_cost":"예상 비용","tip":"팁","faq_title":"자주 묻는 질문","related_tools":"관련 도구","share":"공유","print":"인쇄","copy":"복사","copied":"복사됨!","close":"닫기","more_options":"더 많은 옵션","warm_season":"난지형","cool_season":"한지형","full_sun":"양지","partial_sun":"반양지","shade":"음지","new_lawn":"새 잔디밭","overseeding":"보파기","regular":"일반","starter":"스타터","winter_prep":"겨울 준비","unit_acres":"에이커","skip_to_content":"콘텐츠로 건너뛰기","lbs":"파운드","gallons":"갤런","minutes":"분","cu_yd":"세제곱야드","cu_ft":"세제곱피트","cu_m":"세제곱미터","unit_l":"L"},"cookie_banner":{"message":"계산기 작동에 필요한 필수 쿠키와 사이트 개선을 위한 선택적 분석 쿠키를 사용합니다.","essential_only":"필수만","accept_all":"모두 허용","customize":"맞춤 설정"},"footer":{"copyright":"© 2026 TurfCalculator. 모두를 위한 무료 잔디 계산기.","disclaimer_short":"계산 결과는 추정치입니다. 지역 공급업체에서 확인하세요.","privacy":"개인정보","terms":"약관","disclaimer":"면책","cookies":"쿠키"},"home":{"h1":"무료 잔디 및 잔디밭 계산기","meta_title":"TurfCalculator — 무료 잔디 및 잔디밭 계산기","meta_description":"잔디밭을 위한 무료 잔디, 씨앗, 비료, 토양, 물 계산기. 30초 안에 정확한 결과. 가입 불필요.","hero_title":"잔디가 얼마나 필요하신가요?","hero_subtitle":"잔디밭 치수를 입력하고 즉시 답변을 받으세요","full_sod_calculator":"→ 전체 잔디 계산기","more_calculators":"더 많은 계산기","popular_questions":"인기 질문","question_1":"잔디 팔레트에 몇 제곱미터가 있나요?","question_2":"잔디 롤 하나는 얼마인가요?","question_3":"양지에 가장 좋은 잔디 종류는?","trust_banner":"✅ 무료 · 🔒 가입 없음 · 📊 업계 표준 공식","popular_question_1":"소드 한 팔레트에 몇 평방피트가 있나요?","popular_question_2":"소드 한 롤은 얼마인가요?","popular_question_3":"전일광에서 가장 좋은 잔디 종류는?","popular_question_4":"필요한 소드 양을 어떻게 계산하나요?","popular_answer_1":"표준 팔레트는 약 500평방피트(약 450롤)를 덮습니다. 소형 팔레트는 약 450평방피트, 대형 팔레트는 최대 700평방피트까지 덮을 수 있습니다.","popular_answer_2":"소드는 평방피트당 약 $0.30–$0.80(설치 포함), 또는 재료만 $0.15–$0.40입니다. 가격은 잔디 종류, 지역, 수량에 따라 다릅니다.","popular_answer_3":"버뮤다그라스, 조이시아, 바히아그라스는 하루 6시간 이상의 직사광선이 있는 전일광 지역에서 잘 자랍니다.","popular_answer_4":"피트 단위로 잔디 길이와 너비를 측정하고 곱하여 평방피트를 구한 다음 롤 크기(보통 10평방피트)로 나눕니다. 폐기물로 10%를 더하세요."},"sod_calculator":{"h1":"잔디 계산기","meta_title":"무료 잔디 계산기 — 잔디가 얼마나 필요한가요? (2026)","meta_description":"필요한 잔디 롤과 팔레트 수를 정확히 계산. 손실률 지원 무료 잔디 계산기. 모든 모양에 적용. 가입 불필요.","length_label":"길이","length_help":"잔디밭의 가장 긴 변을 측정","width_label":"폭","width_help":"잔디밭의 가장 짧은 변을 측정","shape_label":"잔디밭 모양","shape_rectangle":"직사각형","shape_square":"정사각형","shape_circle":"원형","shape_oval":"타원형","shape_triangle":"삼각형","shape_trapezoid":"사다리꼴","side_label":"변","major_axis_label":"장축","minor_axis_label":"단축","base_label":"밑변","height_label":"높이","parallel_a_label":"평행변 A","parallel_b_label":"평행변 B","waste_factor_label":"손실률","waste_simple":"단순 (5%)","waste_normal":"보통 (10%)","waste_complex":"복잡 (15%)","waste_very_complex":"매우 복잡 (20%)","roll_size_label":"잔디 롤 사이즈","roll_standard":"표준 (60×150 cm = 0.9 m²)","roll_mini":"미니 (45×60 cm = 0.27 m²)","roll_large":"대형 (60×200 cm = 1.2 m²)","roll_custom":"사용자 지정 사이즈","custom_roll_width":"롤 폭","custom_roll_length":"롤 길이","results_title":"계산 결과","rolls_needed":"필요 롤 수","pallets_needed":"필요 팔레트 수","estimated_cost":"예상 비용","cost_range":"{low} – {high}","total_area":"총 면적 (손실 포함)","tip_extra":"향후 보수용으로 롤 1개 추가 구매","how_to_h2":"필요한 잔디량 계산 방법","how_to_step1":"잔디밭의 길이와 폭을 미터로 측정합니다.","how_to_step2":"길이 × 폭을 곱하여 제곱미터 면적을 구합니다.","how_to_step3":"절단, 성형, 불규칙한 가장자리를 위해 손실률(5–20%)을 추가합니다.","how_to_step4":"총 면적을 잔디 롤 사이즈로 나눕니다 (보통 롤당 0.9 m²).","how_to_step5":"롤 수를 50으로 나누어 팔레트 수를 추정합니다 (표준 팔레트 = 약 45 m²).","roll_sizes_h2":"잔디 롤 사이즈 설명","roll_sizes_table_header_size":"롤 사이즈","roll_sizes_table_header_coverage":"커버리지","roll_sizes_table_header_use":"적합한 용도","faq":[{"q":"잔디 팔레트에 몇 제곱미터가 있나요?","a":"표준 팔레트는 40–50 제곱미터를 커버하며, 0.9 m² 롤이 45–55개 들어 있습니다. 작은 팔레트는 35 m², 큰 팔레트는 최대 60 m²까지 커버할 수 있습니다. 정확한 팔레트 사이즈는 지역 공급업체에 확인하세요."},{"q":"잔디 롤 하나는 얼마인가요?","a":"잔디는 보통 제곱미터당 3,000–10,000원입니다. 가격은 잔디 종류, 지역, 수량에 따라 다릅니다. 버뮤다와 조이시아는 보통 비싼 편이고, 페스큐는 더 저렴합니다."},{"q":"잔디를 추가로 구매해야 하나요? 얼마나?","a":"네, 곡선, 나무, 가장자리 주변 절단으로 인한 손실을 위해 항상 5–15%를 추가하세요. 단순한 직사각형은 5%, 보통 모양은 10%, 장애물이 많은 복잡하거나 불규칙한 잔디밭은 15–20%를 사용하세요."},{"q":"손실률이란 무엇이며 왜 필요한가요?","a":"손실률은 곡선, 산책로, 나무, 가장자리 주변의 절단 및 성형 중 손실되는 잔디를 고려합니다. 이것이 없으면 잔디가 부족할 수 있고 두 번째 주문이 필요할 수 있습니다 — 두 번째 주문은 첫 번째 배치와 색상이나 신선도가 맞지 않을 수 있습니다."},{"q":"잔디는 시공 전 얼마나 보관할 수 있나요?","a":"서늘한 날씨에는 배송 후 24시간 이내, 더운 날씨에는 12시간 이내에 시공해야 합니다. 너무 오래 방치된 잔디는 열이 발생하고 노랗게 변하며 죽습니다. 잔디 도착 전에 토양 준비를 완료하세요."}],"advanced_toggle":"고급 옵션","advanced_label":"고급","shape_l_shape":"L자형","radius_label":"반경","l_length_label":"메인 길이","l_width_label":"메인 폭","l_extension_label":"확장 길이","l_ext_width_label":"확장 폭"},"lawn_area_calculator":{"h1":"잔디밭 면적 계산기","meta_title":"잔디밭 면적 계산기 — 마당 면적 측정 (2026)","meta_description":"잔디밭 면적을 제곱미터, 헥타르 등으로 계산. 직사각형, 원, 삼각형 및 다중 구역 마당 지원. 무료이고 쉽습니다.","shape_label":"잔디밭 모양","shape_rectangle":"직사각형","shape_square":"정사각형","shape_circle":"원형","shape_oval":"타원형","shape_triangle":"삼각형","shape_trapezoid":"사다리꼴","length_label":"길이","width_label":"폭","side_label":"변","diameter_label":"지름","major_axis_label":"장축","minor_axis_label":"단축","base_label":"밑변","height_label":"높이","parallel_a_label":"평행변 A","parallel_b_label":"평행변 B","zone_label":"구역 {number}","remove_zone":"제거","your_lawn":"잔디밭","total_area":"총 면적","conversions":"환산","subtract_zone_label":"제외 구역 {number}","how_to_measure_h2":"잔디용 마당 측정 방법","how_to_measure_p1":"단순한 직사각형 잔디밭의 경우 줄자로 길이와 폭을 측정하여 곱합니다.","how_to_measure_p2":"불규칙한 마당의 경우 면적을 단순한 모양(직사각형, 원, 삼각형)으로 나누어 각각 따로 계산한 다음 합산합니다.","how_to_measure_p3":"잔디가 필요 없는 면적을 뺍니다: 수영장, 진입로, 집 면적, 테라스, 산책로.","common_sizes_h2":"일반적인 잔디밭 크기 참고","common_sizes_small":"작은 도시 마당: 약 200–400 m²","common_sizes_quarter":"교외 1,000 m² 마당","common_sizes_half":"2,000 m² 마당","common_sizes_acre":"1 헥타르: 10,000 m²","faq":[{"q":"불규칙한 모양의 잔디밭은 어떻게 측정하나요?","a":"단순한 모양으로 나눕니다 — 직사각형, 원, 삼각형. 각 구역을 개별적으로 측정하고 각각의 면적을 계산한 다음 모두 합산합니다. '다른 면적 추가' 버튼으로 여러 구역을 입력할 수 있습니다."},{"q":"집과 진입로를 면적에서 빼야 하나요?","a":"네. 실제로 잔디를 깔고 싶은 면적만 측정하세요. '면적 빼기' 옵션으로 집 면적, 진입로, 테라스, 수영장 및 기타 비잔디 면적을 제거할 수 있습니다."},{"q":"측정은 얼마나 정확해야 하나요?","a":"5–10% 이내면 보통 충분합니다. 측정의 작은 오차는 손실률(절단용 여유 잔디)로 커버됩니다. 매우 크거나 비싼 프로젝트의 경우 전문 측량을 고려하세요."},{"q":"구글 지도로 잔디밭을 측정할 수 있나요?","a":"네, 구글 지도와 위성 이미지 도구로 대략적인 추정치를 얻을 수 있습니다. 하지만 상공 뷰는 실제 잔디 면적에 영향을 미치는 경사, 고도 변화, 조경 세부사항을 보여주지 않을 수 있습니다."},{"q":"잔디밭이 경사진 곳에 있으면 어떻게 되나요?","a":"경사진 잔디밭은 평면 측정이 제시하는 것보다 더 많은 잔디가 필요합니다. 실제 표면적이 더 크기 때문입니다. 완만한 경사는 5–10% 추가, 급경사는 10–20% 추가하세요."}],"length_help":"잔디밭의 가장 긴 변을 측정","width_help":"잔디밭의 가장 짧은 변을 측정","send_to_sod":"→ 잔디가 얼마나 필요한지 계산","add_area":"+ 다른 면적 추가","subtract_area":"− 면적 빼기 (수영장, 집, 진입로)"},"grass_type_guide":{"h1":"잔디 종류 비교","meta_title":"잔디밭에 가장 좋은 잔디 종류 — 완전 비교 가이드 (2026)","meta_description":"난지형과 한지형 잔디 종류를 나란히 비교. 양지, 음지, 내답성, 저관리에 가장 좋은 잔디 찾기. 무료 가이드.","warm_cool_toggle":"계절 유형","warm_season_tab":"난지형","cool_season_tab":"한지형","comparison_table_h2":"상세 비교 표","table_header_name":"잔디 종류","table_header_season":"계절","table_header_sun":"일조","table_header_drought":"가뭄 내성","table_header_traffic":"내답성","table_header_maintenance":"관리","table_header_establish":"정착","maintenance_low":"낮음","maintenance_medium":"보통","maintenance_high":"높음","establish_slow":"느림","establish_moderate":"보통","establish_fast":"빠름","tolerance_1":"매우 낮음","tolerance_2":"낮음","tolerance_3":"보통","tolerance_4":"높음","tolerance_5":"매우 높음","pros_label":"장점","cons_label":"단점","best_for_label":"적합한 용도","usda_zones_label":"USDA 지역","grass_types":{"bermudagrass":{"name":"버뮤다그래스","description":"양지에서 잘 자라고 심한 밟힘에 견디는 강인하고 빠르게 퍼지는 난지형 잔디. 더운 기후의 스포츠장과 활동적인 가족 잔디밭의 첫 번째 선택.","pros":["우수한 더위와 가뭄 내성","심한 밟힘에 견디는 내구성","빠른 확산과 자가 복구"],"cons":["겨울에 휴면함 (갈색으로 변함)","양지 필요 — 음지에서는 어려움"],"sun":"full_sun","tags":["warm_season","full_sun","high_traffic"],"drought":"매우 높음","maintenance":"높음"},"zoysia":{"name":"조이시아","description":"추위에 강한 밀도 높은 카펫 같은 난지형 잔디. 정착은 느리지만 잡디를 억제하는 조밀한 잔디밭을 형성하여 기다릴 가치가 있습니다.","pros":["난지형 잔디로서 좋은 내한성","조밀한 생장이 잡디를 억제","정착 후 낮은 물 요구량"],"cons":["느린 정착 — 2시즌 이상 소요될 수 있음","두꺼운 썩은층 형성으로 썩은층 제거 필요"],"sun":"partial_sun","tags":["warm_season","partial_sun","low_maintenance"],"drought":"높음","maintenance":"보통"},"centipede":{"name":"센티피드그래스","description":"'게으른 사람의 잔디'로 알려진 저관리 난지형 잔디. 산성 토양을 선호하며 대부분의 다른 종류보다 적은 비료가 필요합니다.","pros":["매우 낮은 관리 및 시비 요구","산성 토양 조건에 내성","보통 수준의 음지 내성"],"cons":["느린 정착과 확산","낮은 내답성 — 활동적인 마당에 부적합"],"sun":"partial_sun","tags":["warm_season","partial_sun","low_maintenance"],"drought":"보통","maintenance":"낮음"},"st_augustine":{"name":"세인트오거스틴그래스","description":"남부 잔디 중 가장 좋은 음지 내성을 가진 거친 질감의 난지형 잔디. 내염성으로 해안 지역에서 인기.","pros":["난지형 잔디 중 최고의 음지 내성","내염성 — 해안 지역에 적합","잔디 또는 포기에서 빠른 정착"],"cons":["거친 질감이 모든 취향에 맞지 않음","친치벌레 및 질병에 취약"],"sun":"shade","tags":["warm_season","shade","coastal"],"drought":"보통","maintenance":"높음"},"bahiagrass":{"name":"바히아그래스","description":"남부 깊은 곳을 위한 강인하고 가뭄에 강한 난지형 잔디. 다른 잔디가 실패하는 모래빈 토양에서 잘 자랍니다. 개방형 생장 습성과 눈에 띄는 이삭.","pros":["극도의 가뭄 내성 — 강우만으로 생존","척박한 모래 토양에서 생장","낮은 비료 및 관리 요구"],"cons":["개방적이고 거친 생장 습성 — 깔끔한 외관 아님","잦은 예지가 필요한 긴 이삭 생산"],"sun":"full_sun","tags":["warm_season","full_sun","low_maintenance"],"drought":"매우 높음","maintenance":"낮음"},"kentucky_bluegrass":{"name":"켄터키블루그래스","description":"북부 지역의 클래식한 울창하고 짙은 녹색 잔디밭 잔디. 지하 포복경으로 벗겨진 부분을 채워 조밀하고 아름다운 터프를 형성.","pros":["풍부하고 짙은 녹색 — 클래식 잔디밭 외관","지하 포복경으로 자가 복구","우수한 내한성"],"cons":["고관리 — 정기적인 물주기와 시비 필요","종자에서 느린 발아 (2–4주)"],"sun":"full_sun","tags":["cool_season","full_sun","high_maintenance"],"drought":"낮음","maintenance":"높음"},"tall_fescue":{"name":"톨페스큐","description":"가뭄 저항을 위한 깊은 뿌리를 가진 적응성 높은 한지형 잔디. 양지, 음지, 이행 기후에서 잘 자라는 가장 다재다능한 잔디밭 잔디 중 하나.","pros":["우수한 가뭄 저항을 위한 깊은 뿌리 체계","한지형 잔디로서 좋은 음지 내성","켄터키블루그래스에 비해 저관리"],"cons":["퍼지지 않음 — 벗겨진 부분은 재파종 필요","적절히 관리되지 않으면 뭉칠 수 있음"],"sun":"partial_sun","tags":["cool_season","partial_sun","low_maintenance"],"drought":"높음","maintenance":"보통"},"perennial_ryegrass":{"name":"페렌니얼라이그래스","description":"빠른 발아와 고운 질감의 한지형 잔디. 빠른 정착을 위한 종자 혼합과 겨울 푸르름을 위한 난지형 잔디밭 보파기에 자주 사용.","pros":["단 5–7일 만에 발아 — 모든 잔디 중 가장 빠름","고운 질감과 풍부한 녹색","활동적인 잔디밭에 우수한 마모 내성"],"cons":["다른 한지형 잔디보다 내한성이 낮음","단독으로는 단명 — 혼합에서 최적"],"sun":"full_sun","tags":["cool_season","full_sun","quick_establish"],"drought":"낮음","maintenance":"보통"},"fine_fescue":{"name":"파인페스큐","description":"음지와 저관리 상황에서 뛰어난 섬세한 잎의 한지형 잔디. 모든 일반적인 잔디밭 잔디 중 가장 음지에 강함.","pros":["모든 잔디밭 잔디 중 최고의 음지 내성","매우 저관리 — 적은 물과 비료 필요","섬세하고 매력적인 잎 질감"],"cons":["낮은 내답성 — 쉽게 손상됨","덥고 습한 여름에 어려움"],"sun":"shade","tags":["cool_season","shade","low_maintenance"],"drought":"보통","maintenance":"낮음"},"sun_shade_mix":{"name":"일음/그늘 믹스","description":"켄터키블루그래스와 파인페스큐의 혼합으로 양지와 그늘 지역 모두에 적응합니다.","pros":["다양한 빛 조건에 적응","혼합 마당에 적합","보통 관리"],"drought":"보통","maintenance":"보통","sun":"양지에서 부분 그늘"}},"faq":[{"q":"난지형과 한지형 잔디의 차이는 무엇인가요?","a":"난지형 잔디(버뮤다, 조이시아, 세인트오거스틴)는 더운 여름과 온화한 겨울의 남부 기후에서 잘 자랍니다. 겨울에 휴면하고 갈색으로 변합니다. 한지형 잔디(켄터키블루그래스, 페스큐, 라이그래스)는 추운 겨울과 온화한 여름의 북부 기후에서 가장 잘 자랍니다. 선호 지역에서는 일년 내내 푸르게 유지됩니다."},{"q":"양지에 가장 좋은 잔디 종류는?","a":"더운 기후에서는 버뮤다그래스가 양지에 최적의 선택입니다. 차가운 기후에서는 켄터키블루그래스와 페렌니얼라이그래스가 양지에서 가장 좋은 성능을 발휘합니다. 톨페스큐는 혼합 조건에 적합한 좋은 선택입니다."},{"q":"음지에서 가장 잘 자라는 잔디는?","a":"파인페스큐는 가장 음지 내성이 높은 한지형 잔디입니다. 더운 기후에서는 세인트오거스틴그래스가 최고의 음지 옵션입니다. 깊은 음지에서 잘 자라는 잔디는 없습니다 — 직사광선이 하루 3시간 미만인 구역은 지피식물이나 멀칭을 고려하세요."},{"q":"난지형과 한지형 잔디를 섞을 수 있나요?","a":"일반적으로 권장하지 않습니다. 생장 계절, 물 요구량, 예지 높이가 다릅니다. 예외는 보파기입니다: 겨울 푸르름을 위해 난지형 잔디밭에 페렌니얼라이그래스를 보파기할 수 있습니다."},{"q":"내답성이 높은 지역에 가장 좋은 잔디는?","a":"버뮤다그래스는 심한 밟힘에 가장 내구성이 높은 난지형 잔디입니다. 한지형 잔디밭에서는 페렌니얼라이그래스와 켄터키블루그래스가 밟힘을 잘 견딥니다. 깊은 뿌리 체계 덕분에 톨페스큐도 좋은 선택입니다."}],"season_toggle_label":"잔디 계절 유형","cards_label":"잔디 종류"},"grass_seed_calculator":{"h1":"잔디 씨앗 계산기","meta_title":"잔디 씨앗 계산기 — 씨앗이 얼마나 필요한가요? (2026)","meta_description":"잔디밭에 필요한 잔디 씨앗량을 계산. 모든 잔디 종류의 파종량 지원 무료 계산기. 새 잔디밭 또는 보파기. 가입 불필요.","area_label":"잔디밭 면적","area_help":"잔디밭 면적을 제곱미터로 입력","grass_type_label":"잔디 종류","project_type_label":"프로젝트 유형","project_new_lawn":"새 잔디밭","project_overseeding":"보파기","results_seed_needed":"필요한 씨앗","results_bags":"필요한 봉지 수","results_rate":"파종량","results_rate_value":"100 m²당 {rate} kg","seed_rate_note":"표시된 파종량은 {project_type}용입니다. 보파기는 새 잔디밭에 비해 약 절반의 파종량을 사용합니다.","tip_timing":"최적의 파종 시기: 한지형 잔디는 초가을, 난지형 잔디는 늦봄.","how_to_h2":"잔디 씨앗량 계산 방법","how_to_step1":"잔디밭 면적을 제곱미터로 측정합니다.","how_to_step2":"잔디 종류를 선택 — 각각 권장 파종량이 다릅니다.","how_to_step3":"새 잔디밭 또는 보파기를 선택 — 보파기는 약 절반의 씨앗이 필요합니다.","how_to_step4":"계산기가 100 m²당 파종량을 총 면적에 적용합니다.","faq":[{"q":"제곱미터당 잔디 씨앗이 얼마나 필요한가요?","a":"잔디 종류에 따라 다릅니다. 켄터키블루그래스는 새 잔디밭에 100 m²당 약 0.2–0.3 kg이 필요하고, 톨페스큐는 100 m²당 0.6–0.8 kg이 필요합니다. 보파기 파종량은 새 잔디밭 파종량의 약 절반입니다."},{"q":"잔디 씨앗을 너무 많이 뿌릴 수 있나요?","a":"네. 과파종은 물, 영양분, 빛에 대한 경쟁을 일으켜 질병에 취약한 약하고 가느다란 잔디가 됩니다. 잔디 종류의 권장 파종량을 따르세요."},{"q":"씨앗을 뿌려야 하나요, 잔디를 깔아야 하나요?","a":"잔디는 즉시 잔디밭을 얻을 수 있지만 씨앗보다 10–20배 비쌉니다. 씨앗은 정착에 4–8주가 걸리지만 훨씬 저렴합니다. 씨앗은 넓은 면적과 인내심 있는 주택 소유자에게 최적; 잔디는 빠른 결과와 침식에 취약한 경사지에 최적."},{"q":"잔디 씨앗을 뿌리기 가장 좋은 시기는?","a":"한지형 잔디: 초가을(9월–10월) 토양이 따뜻하고 공기가 시원할 때. 난지형 잔디: 늦봄(5월–6월) 토양 온도가 18–21°C에 도달했을 때. 여름 더위에 파종하는 것은 피하세요."},{"q":"잔디 씨앗 발아는 얼마나 걸리나요?","a":"페렌니얼라이그래스: 5–7일. 톨페스큐: 7–12일. 켄터키블루그래스: 14–28일. 파인페스큐: 7–14일. 난지형 잔디: 14–30일. 발아 중에는 토양을 지속적으로 촉촉하게 유지하세요."}],"st_augustine":"세인트오거스틴그래스","sod_only_msg":"보통 잔디로만 심어집니다 — 씨앗은 일반적으로 구하기 어렵습니다.","lb_bags":"파운드 봉지"},"fertilizer_calculator":{"h1":"비료 계산기","meta_title":"잔디밭 비료 계산기 — 비료를 얼마나 살포해야 하나요 (2026)","meta_description":"잔디밭에 살포할 비료량을 정확히 계산. 일반, 스타터, 겨울용 비료 무료 계산기. 잔디밭 면적과 잔디 종류 기반. 가입 불필요.","area_label":"잔디밭 면적","area_help":"잔디밭 면적을 제곱미터로 입력","fertilizer_type_label":"비료 유형","type_regular":"일반","type_starter":"스타터","type_winter":"겨울 준비","type_regular_desc":"생장기의 확립된 잔디밭용","type_starter_desc":"새 씨앗이나 잔디용 — 뿌리 생장을 위한 높은 인","type_winter_desc":"잔디의 겨울 휴면 준비를 위한 가을 시비","results_fertilizer_needed":"필요한 비료","results_bags":"필요한 봉지 수","results_application_rate":"시비량","results_rate_value":"100 m²당 {rate} kg","results_when_to_apply":"시비 시기","when_regular":"활발한 생장기인 봄과 가을에 시비.","when_starter":"파종 또는 잔디 설치 시 시비.","when_winter":"늦가을, 지상부 생장이 멈춘 후 땅이 얼기 전에 시비.","tip_watering":"영양분을 활성화하고 화상을 방지하기 위해 시비 후 24시간 이내에 물을 주세요.","how_to_h2":"비료량 계산 방법","how_to_step1":"잔디밭 면적을 제곱미터로 측정합니다.","how_to_step2":"잔디밭의 현재 요구에 따라 비료 유형을 선택합니다.","how_to_step3":"계산기가 100 m²당 권장 질소량을 적용합니다.","how_to_step4":"결과는 필요한 총 킬로그램 수와 구매할 봉지 수를 보여줍니다.","faq":[{"q":"잔디밭에 비료를 얼마나 살포해야 하나요?","a":"일반적인 기준은 시비당 100 m²당 0.1 kg의 실제 질소입니다. 대부분의 주택 소유자는 연간 2–4회 비료를 살포합니다. 이 계산기는 표준 N-P-K 비율을 사용하여 필요한 총 제품량을 결정합니다."},{"q":"스타터 비료란?","a":"스타터 비료는 새 잔디의 뿌리 발달을 촉진하기 위해 더 높은 인 함량(N-P-K의 가운데 숫자)을 가지고 있습니다. 새 잔디 파종이나 잔디 설치 시 사용하세요. 잔디밭이 확립된 후 일반 비료로 전환하세요."},{"q":"겨울 비료는 언제 살포해야 하나요?","a":"늦가을, 보통 10월–11월에 잔디의 지상부 생장이 멈춘 후 땅이 얼기 전에 살포하세요. 이것은 뿌리가 겨울 생존과 봄 새싹을 위해 에너지를 저장하는 데 도움이 됩니다."},{"q":"잔디밭에 비료를 너무 많이 줄 수 있나요?","a":"네. 과비료는 잔디를 태울 수 있고, 뿌리를 희생하여 과도한 지상부 생장을 유발하며, 수로를 오염시킬 수 있습니다. 항상 권장량을 따르고 라벨이 지시하는 것 이상으로 살포하지 마세요."},{"q":"비오기 전과 후, 어느 쪽에 비료를 살포해야 하나요?","a":"마른 잔디에 비료를 살포하고 24시간 이내에 물을 주세요. 폭우 전에 살포하지 마세요 — 비료가 흡수되기 전에 씻겨갈 수 있습니다. 살포 후 가벼운 비는 괜찮으며 물주기에 도움이 됩니다."}],"timing_starter":"새 잔디 조성이나 보파기 시 시용. 이른 봄이나 가을이 가장 좋습니다.","timing_winter":"첫 서리 전 늦가을(10월~11월)에 시용하여 뿌리를 겨울에 대비시키세요.","timing_maintenance":"활발한 성장기에 시용. 서늘한 계절: 봄과 가을. 따뜻한 계절: 늦봄부터 여름."},"lawn_water_calculator":{"h1":"잔디밭 물 계산기","meta_title":"잔디밭 물 계산기 — 잔디밭에 물이 얼마나 필요한가요? (2026)","meta_description":"잔디밭이 주당 필요한 물량을 계산. 잔디 종류와 면적 기반 무료 물 계산기. 가입 불필요.","area_label":"잔디밭 면적","area_help":"잔디밭 면적을 제곱미터로 입력","grass_type_label":"잔디 종류","results_weekly_water":"주간 물 필요량","results_minutes_per_session":"회당 분수","results_sessions_per_week":"주간 횟수","results_gallons_per_week":"주간 리터","weekly_water_value":"{gallons} 리터","sessions_value":"주 {count} 회","minutes_value":"회당 {minutes} 분","tip_watering_depth":"깊고 드물게 물을 주세요. 각 세션에서 토양을 15cm 깊이까지 적시는 것을 목표로.","tip_early_morning":"증발과 질병 위험을 줄이기 위해 이른 아침(5–9시)에 물을 주세요.","how_to_h2":"잔디밭에 물이 얼마나 필요한가요?","how_to_step1":"대부분의 잔디밭은 강우 포함 주당 25–38 mm의 물이 필요합니다.","how_to_step2":"깊은 뿌리 생장을 위해 주간 물량을 2–3회로 나눕니다.","how_to_step3":"각 세션은 약 12 mm의 물을 공급해야 합니다.","how_to_step4":"우량계나 빈 참치캔으로 스프링클러 출력을 측정합니다.","faq":[{"q":"잔디밭에 몇 분 동안 물을 줘야 하나요?","a":"대부분의 스프링클러는 30분에 약 12 mm를 공급합니다. 주당 25 mm가 필요한 일반적인 잔디밭의 경우 세션당 30분, 주 2–3회 물을 주세요. 실제 시간은 스프링클러 유형과 수압에 따라 다릅니다 — 우량계로 측정하세요."},{"q":"매일 주는 것과 며칠마다 주는 것 중 어느 것이 더 좋나요?","a":"매일 가볍게 주는 것보다 주 2–3회 깊이 주세요. 깊고 드문 물주기는 깊은 뿌리 생장을 촉진하여 잔디밭의 가뭄 내성을 높입니다. 매일 얕은 물주기는 약하고 얕은 뿌리를 촉진합니다."},{"q":"하루 중 언제 잔디밭에 물을 줘야 하나요?","a":"이른 아침(5–9시)이 이상적입니다. 바람이 잔잔하고 기온이 낮으며 물이 증발하기 전에 스며들 시간이 있습니다. 저녁 물주기는 피하세요 — 잔디가 밤새 젖어 질병 위험이 증가합니다. 한낮의 물주기는 증발로 물을 낭비합니다."},{"q":"잔디밭에 물이 필요한지 어떻게 알 수 있나요?","a":"잔디 위를 걸어보세요 — 발자국이 몇 분 이상 보인다면 잔디밭에 물이 필요합니다. 잎이 세로로 접히거나 말리거나 청회색으로 변하는 것도 가뭄 스트레스의 징후입니다."},{"q":"계절에 따라 물주기를 조절해야 하나요?","a":"네. 여름 더위에는 물주기 빈도를 높이세요. 봄과 가을에는 줄이세요. 한지형 잔디의 겨울에는 2–3주 강우가 없을 때만 물을 주세요. 난지형 잔디는 휴면 중 물이 거의 또는 전혀 필요하지 않습니다."}]},"soil_calculator":{"h1":"토양 계산기","meta_title":"표토 계산기 — 토양이 얼마나 필요한가요? (2026)","meta_description":"잔디밭이나 정원에 필요한 표토, 퇴비, 메우기 흙의 양을 계산. 세제곱미터 및 봉지 단위 결과. 무료이고 쉽습니다.","area_label":"면적","area_help":"덮을 면적을 제곱미터로 입력","depth_label":"깊이","depth_help":"권장: 새 잔디밭은 10–15 cm, 탑드레싱은 2.5–5 cm","results_volume":"필요한 부피","results_cubic_yards":"세제곱야드","results_cubic_feet":"세제곱피트","results_cubic_meters":"세제곱미터","results_bags":"봉지 환산","bag_size":"{size} L 봉지","tip_depth":"새 잔디밭에는 10–15 cm의 표토가 권장됩니다. 기존 잔디밭의 탑드레싱에는 2.5–5 cm면 충분합니다.","tip_compaction":"다짐을 고려하여 10–15% 추가로 주문하세요. 토양은 펴고 물을 준 후 가라앉습니다.","how_to_h2":"토양 부피 계산 방법","how_to_step1":"덮고자 하는 면적을 제곱미터로 측정합니다.","how_to_step2":"토양의 깊이를 결정합니다 (센티미터).","how_to_step3":"면적 × 깊이(미터)를 곱하여 세제곱미터를 구합니다.","how_to_step4":"세제곱미터를 세제곱야드로 변환하려면 0.7646으로 나눕니다.","faq":[{"q":"새 잔디밭에 표토가 얼마나 필요한가요?","a":"새 잔디밭에는 10–15 cm의 표토가 필요합니다. 100 m² 면적에 깊이 10 cm면 약 10 m³입니다. 다짐용으로 10–15% 추가로 주문하세요."},{"q":"토양 봉지에 몇 세제곱미터가 있나요?","a":"표준 표토 봉지는 20–50리터입니다. 1 세제곱미터는 1,000리터입니다. 따라서 봉지 크기에 따라 1 세제곱미터당 20–50봉지가 필요합니다. 대규모 프로젝트에서는 산물 구매가 보통 더 저렴합니다."},{"q":"표토와 정원토의 차이는 무엇인가요?","a":"표토는 정지와 메우기에 적합한 천연 토양의 최상층입니다. 정원토는 표토에 퇴비와 유기물을 혼합한 것으로 식재 베드에 더 적합합니다. 새 잔디밭에는 표토를, 정원에는 정원토를 사용하세요."},{"q":"잔디 아래 표토는 얼마나 깊어야 하나요?","a":"잔디를 깔기 전에 최소 10 cm의 양질 표토가 필요합니다. 장기적인 뿌리 건강을 위해서는 15 cm가 이상적입니다. 기존 토양이 빈약하다면 잔디를 깔기 전에 5–10 cm의 표토를 추가하고 자연 토양과 섞으세요."},{"q":"잔디를 깔기 전에 퇴비를 추가해야 하나요?","a":"네, 2.5–5 cm의 퇴비를 뿌리고 상부 10–15 cm 토양과 섞으면 배수, 영양 함량, 뿌리 정착이 개선됩니다. 퇴비는 특히 점토질이나 모래 토양에 중요합니다."}]},"area_converter":{"h1":"면적 변환기","meta_title":"면적 변환기 — 제곱미터, 헥타르, 에이커 등 (2026)","meta_description":"제곱미터, 헥타르, 에이커, 평방야드 등 간 변환. 실시간 결과 무료 면적 변환기. 가입 불필요.","from_label":"변환 전","to_label":"변환 후","value_label":"값","result_label":"결과","swap":"교체","unit_sqin":"제곱인치","unit_sqft":"제곱피트","unit_sqyd":"제곱야드","unit_sqm":"제곱미터","unit_ac":"에이커","unit_ha":"헥타르","unit_sqmi":"제곱마일","conversion_formula":"{from_unit} → {to_unit}","formula_text":"환산 공식","common_conversions_h2":"일반적인 변환","faq":[{"q":"1 헥타르는 몇 제곱미터인가요?","a":"1 헥타르는 10,000 제곱미터입니다. 이는 약 100 m × 100 m 정사각형에 해당합니다. 헥타르는 한국에서 토지 면적 측정에 일반적으로 사용되는 단위입니다."},{"q":"제곱미터를 제곱피트로 변환하려면?","a":"제곱미터에 10.764를 곱하여 제곱피트를 구합니다. 예: 100 m² × 10.764 = 1,076.4 ft². 빠른 추정을 위해서는 10.8을 곱하세요."},{"q":"내 땅은 몇 헥타르인가요?","a":"제곱미터 단위의 면적을 10,000으로 나눕니다. 예: 1,000 m² 토지 = 0.1 헥타르. 2,000 m² 토지 = 0.2 헥타르."},{"q":"에이커란 무엇인가요?","a":"에이커는 주로 영미권 국가에서 사용되는 면적 단위로, 약 4,047 제곱미터 또는 약 0.4047 헥타르에 해당합니다. 한국에서는 거의 사용되지 않으며 표준 단위는 헥타르입니다."},{"q":"1 제곱미터는 몇 제곱야드인가요?","a":"1 제곱미터는 약 1.196 제곱야드입니다. 제곱미터를 제곱야드로 변환하려면 1.196을 곱하세요. 예: 100 m² × 1.196 = 119.6 yd²."}],"unit_sqcm":"평방센티미터","copy":"복사","conversion_units":{"sqft":"제곱피트","sqm":"제곱미터","ac":"에이커","ha":"헥타르","sqyd":"제곱야드","sqin":"제곱인치","sqmi":"제곱마일","sqcm":"제곱센티미터"},"conversion_title_template":"{from}에서 {to} 변환기","conversion_desc_template":"{from}을(를) {to}(으)로 즉시 변환. 정확한 결과를 제공하는 무료 온라인 면적 변환기."},"lawn_care_calendar":{"h1":"잔디 관리 캘린더","meta_title":"잔디 관리 캘린더 — 월별 일정 (2026)","meta_description":"난지형 및 한지형 잔디의 월별 관리 일정. 시비, 예지, 물주기, 보파기 시기를 알 수 있는 무료 가이드.","season_toggle_label":"잔디 계절 유형","phase_dormant":"휴면","phase_pre_season":"시즌 전","phase_active_growth":"활발한 생장","phase_transition":"이행기","phase_preparation":"준비","priority_critical":"중요","priority_recommended":"권장","priority_optional":"선택","month_names":["1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"],"warm_season":{"january":{"phase":"휴면","tasks":["얼거나 서리가 앉은 잔디 위 걷기 피하기","예지기 정비 — 날 갈기 및 오일 교환","연간 잔디 관리 목표와 예산 계획"],"tip":"비시즌 가격으로 씨앗과 자재를 주문하기 좋은 시기."},"february":{"phase":"휴면","tasks":["월 말에 잡디 방지를 위한 발아전 제초제 살포","토양 pH 및 영양 수준 검사","잔디 표면의 잔해 및 낙엽 제거"],"tip":"발아전 제초제 시기가 중요 — 토양 온도가 13°C에 도달하기 전에 살포."},"march":{"phase":"시즌 전","tasks":["2월에 발아전 제초제를 살포하지 않았다면 살포","썩은층 축적물 긁어내기 및 제거","잔디가 파래지기 시작하면 예지 시작"],"tip":"첫 예지에서 너무 짧게 깎지 마세요 — 초장의 ⅓ 이상 제거하지 마세요."},"april":{"phase":"활발한 생장","tasks":["잔디가 파래질 때 첫 번째 비료 살포","잔디 종류에 권장되는 높이로 정기 예지 시작","발아후 제초제로 잡디 부분 처리"],"tip":"잔디가 완전히 파래질 때까지 시비 대기 — 이른 시비는 잡디를 키웁니다."},"may":{"phase":"활발한 생장","tasks":["정기 예지 계속 — 초장의 ⅓ 이상 깎지 않기","두 번째 비료 살포","유충 피해 모니터링 및 필요시 처리"],"tip":"기온이 상승함에 따라 예지 높이를 약간 높여 스트레스 감소."},"june":{"phase":"활발한 생장","tasks":["주 1–2회 깊게 물주기 (총 25 mm)","해충 징후 주시 및 신속 대응","지속적인 잡디에 부분 처리 적용"],"tip":"증발과 질병 위험을 줄이기 위해 이른 아침에 물주기."},"july":{"phase":"활발한 생장","tasks":["건조 기간 중 깊은 물주기 계속","열 스트레스 감소를 위해 예지 높이 높이기","한더위에 시비 피하기 — 잔디 화상 위험"],"tip":"잔디가 더위/가뭄으로 휴면에 들어가면 비료로 억지로 파랗게 만들지 마세요."},"august":{"phase":"이행기","tasks":["습한 날씨에 곰팡이 질병 모니터링","필요에 따라 물주기 계속","원하는 경우 가을 보파기 계획 시작"],"tip":"8월 하순은 가을 프로젝트용 씨앗과 자재 주문 시기."},"september":{"phase":"이행기","tasks":["휴면 전 뿌리 강화를 위한 가을 비료 살포","필요시 얇거나 벗겨진 부분 보파기","생장이 느려짐에 따라 예지 빈도 감소"],"tip":"가을 시비는 난지형 잔디에게 연중 가장 중요한 작업."},"october":{"phase":"준비","tasks":["월 중순~하순에 겨울 비료 살포","잔디가 자라는 것을 멈출 때까지 예지 계속","잔디 질식 방지를 위해 낙엽 긁어모으기"],"tip":"낙엽을 잔디 위에 며칠 이상 방치하지 마세요 — 햇빛을 차단합니다."},"november":{"phase":"준비","tasks":["시즌 마지막 예지 — 평소보다 약간 짧게","정원 도구 청소 및 보관","한지형 잡디 방지를 위한 겨울 발아전 제초제 살포"],"tip":"약간 짧은 마지막 예지는 겨울 동안 매트화 및 질병 위험을 줄입니다."},"december":{"phase":"휴면","tasks":["서리가 앉은 잔디 위 걷기 피하기","남은 비료와 화학제 적절히 보관","한 해를 되돌아보고 다음 시즌 개선 계획"],"tip":"겨울은 봄 프로젝트를 위한 잔디 품종 조사 및 비교에 좋은 시기."}},"cool_season":{"january":{"phase":"휴면","tasks":["손상 방지를 위해 얼은 잔디 위 걷기 피하기","예지기 정비 — 날 갈기 및 오일 교환","다가오는 시즌의 잔디 관리 목표 계획"],"tip":"겨울 가격으로 씨앗과 자재를 주문하기 좋은 시기."},"february":{"phase":"시즌 전","tasks":["토양 pH 및 영양 수준 검사","월 중순~하순에 발아전 제초제 살포","잔해 긁어모으고 잔디 표면 청소"],"tip":"발아전 제초제 시기가 중요 — 토양 온도가 13°C에 도달하기 전에 살포."},"march":{"phase":"시즌 전","tasks":["2월에 발아전 제초제를 살포하지 않았다면 살포","겨울 잔해와 눈곰팡이 가볍게 제거","잔디가 8+ cm 높이에 도달하면 예지 시작"],"tip":"봄 정리를 서두르지 마세요 — 다짐을 피하기 위해 땅이 단단하고 마를 때까지 대기."},"april":{"phase":"활발한 생장","tasks":["시즌 첫 비료 살포","권장 높이로 정기 예지 시작","얇거나 벗겨진 부분 보파기"],"tip":"봄은 보파기에 두 번째로 좋은 시기 — 가을이 최적이지만 작은 보수에는 봄도 가능."},"may":{"phase":"활발한 생장","tasks":["정기 예지와 물주기 계속","광엽 잡디 부분 처리","습한 조건에서 질병 모니터링"],"tip":"잔디 깎은 것을 잔디밭에 남겨두세요 — 토양에 질소를 환원합니다 (무료 비료)."},"june":{"phase":"활발한 생장","tasks":["여름 열 스트레스 감소를 위해 예지 높이 높이기","깊고 드물게 물주기 — 주당 25–38 mm","유충 피해 모니터링 및 임계값 초과시 처리"],"tip":"더 긴 잔디는 토양을 그늘지게 하고 증발을 줄이며 잡디를 억제합니다."},"july":{"phase":"이행기","tasks":["덥고 건조한 기간 중 깊은 물주기 계속","여름 더위에 시비 피하기","갈색반점 및 기타 곰팡이 질병 모니터링"],"tip":"극심한 더위에 잔디가 휴면에 들어가면 기온이 내려가면 회복됩니다."},"august":{"phase":"이행기","tasks":["가을 보파기 및 통기 계획 시작","가을 프로젝트용 씨앗과 자재 주문","필요에 따라 물주기 계속"],"tip":"8월 하순~9월 상순은 한지형 잔디밭 보파기에 최적의 시기."},"september":{"phase":"활발한 생장","tasks":["다짐 완화를 위해 잔디밭 통기","얇은 부분 보파기 — 올해 최적의 시기","가을 비료 살포"],"tip":"통기와 함께하는 가을 보파기는 최적의 발아를 위해 씨앗이 토양에 직접 닿게 합니다."},"october":{"phase":"활발한 생장","tasks":["올해 가장 중요한 비료 살포 (가을 시비)","잔디가 자라는 한 예지 계속","질식 방지를 위해 정기적으로 낙엽 긁어모으기"],"tip":"가을 시비는 겨울 생존과 봄 새싹을 위한 뿌리 비축을 구축합니다."},"november":{"phase":"준비","tasks":["월 말에 겨울 비료 살포","시즌 마지막 예지 — 약간 짧게","정원 도구 청소 및 겨울 준비"],"tip":"마지막 가을 비료 살포는 일년 중 가장 중요합니다."},"december":{"phase":"휴면","tasks":["서리나 눈이 덮인 잔디 위 걷기 피하기","남은 비료와 화학제 적절히 보관","내년 잔디 개선 계획"],"tip":"겨울은 새 잔디 품종 조사와 봄 프로젝트 계획에 이상적."}},"faq":[{"q":"잔디 관리 일정은 언제 시작해야 하나요?","a":"늦겨울(2월)에 잔디밭 모니터링을 시작하세요. 첫 활동 작업은 보통 토양 온도가 13°C에 도달하는 이른 봄에 시작됩니다. 한지형 잔디는 봄에 더 일찍 깨어나고; 난지형 잔디는 토양이 안정적으로 따뜻해질 때 더 늦게 시작합니다."},{"q":"잔디밭에 얼마나 자주 비료를 살포해야 하나요?","a":"난지형 잔디: 연 3–4회 (봄~초가을). 한지형 잔디: 연 2–3회, 가장 중요한 살포는 가을. 극심한 더위나 잔디가 휴면일 때 시비를 피하세요."},{"q":"잔디밭 통기에 가장 좋은 시기는?","a":"한지형 잔디는 초가을(9월–10월)에 통기하세요. 난지형 잔디는 잔디가 활발히 자라고 빠르게 회복할 수 있는 늦봄이나 초여름(5월–6월)에 통기하세요."},{"q":"잔디 깎은 것을 잔디밭에 남겨두어야 하나요?","a":"네, 대부분의 경우. 잔디 깎은 것은 빠르게 분해되어 토양에 질소와 유기물을 환원합니다. 이것은 비료 필요량을 최대 25%까지 줄일 수 있습니다. 잔디가 매우 길거나 병에 걸렸거나 잡디 씨앗 시기에만 깎은 것을 수거하세요."},{"q":"발아전 제초제는 언제 살포해야 하나요?","a":"토양 온도가 3일 이상 연속으로 13°C에 도달하기 전 이른 봄에 살포하세요. 이것은 피 및 기타 일년생 잡디의 발아를 방지합니다. 6–8주 후 두 번째 살포는 연장 방제 효과를 제공합니다."}]},"about":{"h1":"TurfCalculator 소개","meta_title":"TurfCalculator 소개 — 모두를 위한 무료 잔디 계산기","meta_description":"TurfCalculator에 대해 알아보기 — 주택 소유자를 위한 무료, 정확한 잔디 및 turf 계산기. 가입 없음, 데이터 수집 없음, 빠른 답변만.","mission_h2":"우리의 미션","mission_p1":"TurfCalculator은 주택 소유자와 DIY 애호가에게 무료, 정확하고 빠른 잔디 계산기를 제공합니다. 잔디를 구매하든, 씨앗을 뿌리든, 잔디 관리 일정을 계획하든 30초 이내에 필요한 수치를 제공합니다.","mission_p2":"가입 없음. 이메일 없음. 데이터 수집 없음. 그저 작동하는 도구.","how_we_calculate_h2":"계산 방법","how_we_calculate_p1":"모든 계산기는 업계 표준 공식과 대학 연장 서비스, USDA 지침, 잔디 연구 기관의 데이터를 사용합니다. 출처를 인용하고 데이터를 최신으로 유지합니다.","how_we_calculate_p2":"모든 계산은 브라우저에서 이루어집니다 — 입력이나 결과를 절대 보지 않습니다. 데이터는 기기에 남습니다.","who_for_h2":"누구를 위한 것인가요?","who_for_p1":"잔디 설치나 잔디밭 개조를 계획하는 주택 소유자.","who_for_p2":"씨앗, 비료 또는 토양을 얼마나 구매해야 하는지 알고 싶은 DIY 정원사.","who_for_p3":"정원센터 통로에 서서 \"얼마나 필요하지?\"라고 궁금해하는 모든 사람.","disclaimer_h2":"면책 조항","disclaimer_p":"계산기는 업계 평균을 기반으로 추정치를 제공합니다. 실제 수량은 특정 현장 조건, 지역 공급업체 사양 및 시공 방법에 따라 다를 수 있습니다. 구매 전 항상 지역 공급업체에서 수량을 확인하세요."},"privacy_policy":{"h1":"개인정보 처리방침","meta_title":"개인정보 처리방침 — TurfCalculator","meta_description":"TurfCalculator 개인정보 처리방침. 개인 데이터를 수집하지 않습니다. 모든 계산은 브라우저에서 이루어집니다. 쿠키 및 분석 관행에 대해 알아보기.","last_updated":"최종 업데이트: 2026년 5월","intro_p":"TurfCalculator은 귀하의 개인정보를 존중합니다. 이 방침은 수집하는 데이터, 사용 방법 및 귀하의 권리를 설명합니다.","data_collection_h2":"수집하는 데이터","data_collection_p1":"개인 데이터를 수집하지 않습니다. 계정, 이메일, 이름 또는 개인 식별 정보를 요구하지 않습니다.","data_collection_p2":"모든 계산기 입력과 결과는 브라우저에서 완전히 처리됩니다. 계산 내용을 절대 보거나 저장하거나 전송하지 않습니다.","analytics_h2":"분석","analytics_p1":"방문자가 사이트를 어떻게 사용하는지 이해하기 위해 Google Analytics 4를 사용할 수 있습니다. GA4는 익명화된 IP 주소를 사용하며 개인 식별 정보를 수집하지 않습니다.","analytics_p2":"분석은 쿠키 배너를 통해 동의한 후에만 활성화됩니다.","cookies_h2":"쿠키","cookies_p1":"필수 쿠키: 언어 기본 설정은 브라우저의 localStorage에 저장됩니다 (쿠키가 아님). 사이트 기능에 필요합니다.","cookies_p2":"분석 쿠키: 동의 후에만 Google Analytics에 의해 설정됩니다. _ga 및 _gid 쿠키가 포함됩니다.","cookies_p3":"광고 쿠키: 향후 동의 후에만 Google AdSense에 의해 설정될 수 있습니다.","third_party_h2":"제3자 서비스","third_party_p1":"Cloudflare: 호스팅 및 CDN 제공업체. 보안 및 성능을 위해 기술 데이터를 수집할 수 있습니다.","third_party_p2":"Google Analytics: 위 분석 섹션 참조.","third_party_p3":"Google AdSense: 향후 광고를 표시할 수 있습니다. 위 쿠키 섹션 참조.","gdpr_h2":"개인정보보호법 준수","gdpr_p1":"개인 데이터를 수집하지 않으므로 대부분의 개인정보보호법 의무가 핵심 서비스에 적용되지 않습니다.","gdpr_p2":"쿠키 동의 배너를 통해 분석 및 광고 쿠키를 거부할 권리가 있습니다.","gdpr_p3":"데이터에 관한 질문은 아래 이메일 주소로 문의해 주세요.","ccpa_h2":"CCPA 준수","ccpa_p1":"개인 정보를 판매하지 않습니다. 분석 및 광고 서비스를 넘어 제3자와 개인 정보를 공유하지 않습니다.","ccpa_p2":"핵심 계산기 서비스에 의해 개인 정보가 수집되지 않습니다.","contact_h2":"연락처","contact_p":"개인정보 관련 문의는 소개 페이지에 제공된 정보를 통해 연락해 주세요."},"terms":{"h1":"이용약관","meta_title":"이용약관 — TurfCalculator","meta_description":"TurfCalculator 이용약관. 정보 제공 목적으로 제공되는 무료 잔디 및 turf 계산기.","last_updated":"최종 업데이트: 2026년 5월","acceptance_h2":"약관의 수락","acceptance_p":"TurfCalculator을 사용함으로써 이 이용약관에 동의하게 됩니다. 동의하지 않으면 사이트를 사용하지 마세요.","use_h2":"서비스 이용","use_p1":"TurfCalculator은 잔디 및 turf 자재량 추정을 위한 무료 온라인 계산기를 제공합니다. 모든 결과는 정보 제공 목적의 추정치입니다.","use_p2":"계산기를 개인적, 비상업적 목적으로 사용할 수 있습니다. 허가 없이 콘텐츠나 도구를 스크래핑, 복사, 재배포할 수 없습니다.","accuracy_h2":"정확성 면책","accuracy_p1":"계산기 결과는 업계 표준 공식과 평균 데이터를 기반으로 합니다. 실제 자재 요구량은 현장 조건, 공급업체 사양, 시공 방법 및 지역적 요인에 따라 다를 수 있습니다.","accuracy_p2":"구매 전 항상 지역 공급업체에서 수량을 확인하세요. TurfCalculator은 이러한 계산으로 인한 과소 구매에 대해 책임지지 않습니다.","no_liability_h2":"책임 제한","no_liability_p":"TurfCalculator은 어떠한 종류의 보증도 없이 있는 그대로 제공됩니다. 부정확한 자재 추정으로 인한 재정적 손실을 포함하되 이에 국한되지 않는 계산기 사용으로 인해 발생하는 어떠한 손해에 대해서도 책임지지 않습니다.","intellectual_property_h2":"지적 재산","intellectual_property_p":"TurfCalculator의 모든 콘텐츠, 디자인 및 코드는 TurfCalculator의 재산입니다. 서면 허가 없이 도구나 콘텐츠를 복사, 수정, 배포할 수 없습니다.","changes_h2":"약관 변경","changes_p":"이 약관을 수시로 업데이트할 수 있습니다. 변경 후 사이트의 계속 사용은 업데이트된 약관의 수락을 구성합니다."},"disclaimer":{"h1":"면책 조항","meta_title":"면책 조항 — TurfCalculator","meta_description":"TurfCalculator 면책 조항. 계산 결과는 추정치입니다. 자재 구매 전 항상 지역 공급업체에서 확인하세요.","last_updated":"최종 업데이트: 2026년 5월","main_p1":"이 계산기는 업계 표준 공식과 데이터를 기반으로 추정치를 제공합니다. 실제 잔디, 씨앗 및 자재 요구량은 현장 조건, 공급업체 사양 및 시공 방법에 따라 다를 수 있습니다.","main_p2":"구매 전 항상 지역 공급업체에서 수량을 확인하세요. TurfCalculator은 이러한 계산으로 인한 과소 구매에 대해 책임지지 않습니다.","prices_h2":"가격 추정","prices_p":"가격 추정은 범위일 뿐 견적이 아닙니다. 실제 가격은 지역, 공급업체, 잔디 종류, 수량 및 계절에 따라 다릅니다. 현재 가격은 지역 공급업체에 문의하세요.","recommendations_h2":"잔디 종류 추천","recommendations_p":"잔디 종류 정보는 일반적인 조건에 기반한 일반 지침이며 전문 조언이 아닙니다. 지역 기후, 토양 조건 및 미세기후가 잔디 성능에 영향을 미칠 수 있습니다. 구체적인 권장 사항은 지역 잔디 관리 전문가와 상담하세요.","calendar_h2":"잔디 관리 캘린더","calendar_p":"잔디 관리 캘린더는 일반적인 조건과 일반 지침을 기반으로 합니다. 실제 시기는 지역 기후, 날씨 패턴 및 특정 잔디 조건에 따라 다를 수 있습니다. 지역 연장 서비스 권장에 따라 시기를 조정하세요.","professional_h2":"전문가 조언","professional_p":"계산기의 결과는 자격을 갖춘 잔디 관리 전문가와의 상담을 대체하지 않습니다. 복잡한 프로젝트, 토양 검사 또는 해충 문제의 경우 지역 전문가와 상담하세요."},"cookie_policy":{"h1":"쿠키 정책","meta_title":"쿠키 정책 — TurfCalculator","meta_description":"TurfCalculator 쿠키 정책. 사용하는 쿠키, 이유 및 기본 설정 관리 방법에 대해 알아보기.","last_updated":"최종 업데이트: 2026년 5월","what_are_h2":"쿠키란 무엇인가요?","what_are_p":"쿠키는 웹사이트를 방문할 때 기기에 저장되는 작은 텍스트 파일입니다. 사이트가 기본 설정을 기억하고 경험을 개선하는 데 도움이 됩니다.","essential_h2":"필수 쿠키","essential_p1":"사이트가 올바르게 작동하는 데 필요합니다.","essential_p2":"언어 기본 설정: localStorage에 저장됩니다 (전통적인 쿠키가 아님). 방문 간 언어 선택을 기억합니다.","essential_p3":"쿠키 동의: 쿠키 기본 설정을 저장하여 매번 방문할 때마다 다시 묻지 않습니다.","analytics_h2":"분석 쿠키","analytics_p1":"방문자가 사이트를 어떻게 사용하는지 이해하여 개선하는 데 도움이 됩니다.","analytics_cookie_ga":"_ga: 고유 방문자를 구분. 2년 후 만료.","analytics_cookie_gid":"_gid: 일별 고유 방문자를 구분. 24시간 후 만료.","analytics_p2":"분석 쿠키는 쿠키 배너를 통해 동의한 후에만 설정됩니다.","advertising_h2":"광고 쿠키","advertising_p1":"향후 Google AdSense가 개인화된 광고를 표시하기 위해 쿠키를 설정할 수 있습니다.","advertising_p2":"광고 쿠키는 동의한 후에만 설정됩니다.","advertising_p3":"Google 광고 설정을 통해 개인화된 광고를 거부할 수 있습니다.","managing_h2":"쿠키 기본 설정 관리","managing_p1":"쿠키 배너나 하단의 설정 링크를 사용하여 언제든지 쿠키 기본 설정을 변경할 수 있습니다.","managing_p2":"브라우저 설정을 통해 쿠키를 관리할 수도 있습니다. 모든 쿠키를 비활성화하면 사이트 기능에 영향을 미칠 수 있습니다.","managing_p3":"온라인 추적 및 권리에 대한 자세한 내용은 지역 데이터 보호 기관의 웹사이트를 방문하세요."},"sod_calc":{"total_area_label":"총 면적","area_with_waste":"{waste}% 손실 포함 면적","rolls_needed_roll":"필요한 롤 수 ({roll})","roll_standard_short":"표준 롤","roll_mini_short":"미니 롤","roll_large_short":"대형 롤","price_per_sqft":"sq ft당 가격","cost_help":"총 비용을 추정하려면 sq ft당 현지 가격을 입력하세요."},"fert_calc":{"bags_15lb":"15파운드 봉지","bags_30lb":"30파운드 봉지"},"seed_calc":{"bags_5lb":"5파운드 봉지","bags_20lb":"20파운드 봉지"},"soil_calc":{"bags_2cuft":"2세제곱피트 봉지","bags_075cuft":"0.75세제곱피트 봉지","bags_40lb":"40파운드 봉지","liters":"리터","bags_1cuft":"1 세제곱피트 봉지","bags_15cuft":"1.5 세제곱피트 봉지","results_cubic_yards":"입방 야드"},"area_calc":{"square_feet":"제곱피트","square_meters":"제곱미터","send_to_sod":"잔디 계산기로 보내기 →","subtract":"빼기","add_area":"면적","shape_rectangle":"직사각형","shape_circle":"원형","shape_triangle":"삼각형","length_ft":"길이 (ft)","width_ft":"폭 (ft)","radius_ft":"반경 (ft)","base_ft":"밑변 (ft)","height_ft":"높이 (ft)","square_yards":"평방야드","acres":"에이커"},"lang_name":"한국어"};